@router.post('/exports')
def create_export(request, user):
    target_account = request.json.get('account_id', user.account_id)
    export_id = enqueue_export_job(target_account, user.id)
    return {'export_id': export_id}, 202

def download_export(request, export_id):
    export_row = db.fetch_one('SELECT url, account_id FROM exports WHERE id=%s', (export_id,))
    return redirect(export_row['url'])
